import androidx.room.*

@Entity(tableName = "pending_ai_requests")
data class PendingAiRequest(
    @PrimaryKey(autoGenerate = true) val id: Long = 0,
    val query: String,
    val sessionToken: String,
    val routingContext: String,           // e.g. "ocr", "object-detection", "nlu"
    val createdAtMs: Long,
    val ttlMs: Long = 4 * 60 * 60 * 1000L,  // drop after 4 hours by default
    val retryCount: Int = 0
)

@Entity(tableName = "cached_results")
data class CachedResult(
    @PrimaryKey val queryHash: String,    // SHA-256 of normalized query
    val response: String,
    val cachedAtMs: Long,
    val ttlMs: Long = 24 * 60 * 60 * 1000L
)

@Dao
interface PendingAiRequestDao {
    @Insert
    suspend fun enqueue(request: PendingAiRequest): Long

    @Query("""
        SELECT * FROM pending_ai_requests
        WHERE (createdAtMs + ttlMs) > :nowMs
        ORDER BY id ASC LIMIT 50
    """)
    suspend fun fetchLive(nowMs: Long): List<PendingAiRequest>

    @Query("DELETE FROM pending_ai_requests WHERE (createdAtMs + ttlMs) <= :nowMs")
    suspend fun pruneExpired(nowMs: Long): Int

    @Delete
    suspend fun remove(request: PendingAiRequest)

    @Query("UPDATE pending_ai_requests SET retryCount = retryCount + 1 WHERE id = :id")
    suspend fun incrementRetry(id: Long)
}

@Dao
interface CachedResultDao {
    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun put(result: CachedResult)

    @Query("SELECT * FROM cached_results WHERE queryHash = :hash AND (cachedAtMs + ttlMs) > :nowMs")
    suspend fun get(hash: String, nowMs: Long): CachedResult?

    @Query("DELETE FROM cached_results WHERE (cachedAtMs + ttlMs) <= :nowMs")
    suspend fun pruneExpired(nowMs: Long)
}

import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase
import android.content.Context

@Database(
    entities = [PendingAiRequest::class, CachedResult::class],
    version = 1,
    exportSchema = false
)
abstract class HybridAiDatabase : RoomDatabase() {
    abstract fun pendingRequestDao(): PendingAiRequestDao
    abstract fun cachedResultDao(): CachedResultDao

    companion object {
        @Volatile private var INSTANCE: HybridAiDatabase? = null

        fun getInstance(context: Context): HybridAiDatabase =
            INSTANCE ?: synchronized(this) {
                Room.databaseBuilder(
                    context.applicationContext,
                    HybridAiDatabase::class.java,
                    "hybrid_ai.db"
                ).build().also { INSTANCE = it }
            }
    }
}

import android.content.Context
import androidx.work.*
import kotlinx.coroutines.flow.toList

const val MAX_RETRY_COUNT = 5

class DrainQueueWorker(
    ctx: Context,
    params: WorkerParameters
) : CoroutineWorker(ctx, params) {

    override suspend fun doWork(): Result {
        val db = HybridAiDatabase.getInstance(applicationContext)
        val proxyClient = ClaudeProxyClient(BuildConfig.PROXY_BASE_URL)
        val nowMs = System.currentTimeMillis()

        // Prune expired entries first — they will never be useful
        val dropped = db.pendingRequestDao().pruneExpired(nowMs)
        if (dropped > 0) {
            // Optionally show a notification that some queued queries expired
        }

        val pending = db.pendingRequestDao().fetchLive(nowMs)
        if (pending.isEmpty()) return Result.success()

        var anyFailed = false
        for (entry in pending) {
            if (entry.retryCount >= MAX_RETRY_COUNT) {
                db.pendingRequestDao().remove(entry)
                continue
            }
            try {
                val request = ProxyRequest(
                    query = entry.query,
                    sessionToken = entry.sessionToken,
                    routingReason = entry.routingContext
                )
                val fullResponse = proxyClient
                    .streamQuery(request)
                    .toList()
                    .joinToString("")

                // Cache the result for offline re-use
                db.cachedResultDao().put(
                    CachedResult(
                        queryHash = entry.query.sha256(),
                        response = fullResponse,
                        cachedAtMs = System.currentTimeMillis()
                    )
                )
                db.pendingRequestDao().remove(entry)
            } catch (e: Exception) {
                db.pendingRequestDao().incrementRetry(entry.id)
                anyFailed = true
            }
        }

        return if (anyFailed) Result.retry() else Result.success()
    }
}

fun String.sha256(): String {
    val digest = java.security.MessageDigest.getInstance("SHA-256")
    return digest.digest(toByteArray()).joinToString("") { "%02x".format(it) }
}

fun scheduleDrainOnConnectivity(context: Context) {
    val constraints = Constraints.Builder()
        .setRequiredNetworkType(NetworkType.CONNECTED)
        .build()

    val work = OneTimeWorkRequestBuilder<DrainQueueWorker>()
        .setConstraints(constraints)
        .setBackoffCriteria(BackoffPolicy.EXPONENTIAL, 30, java.util.concurrent.TimeUnit.SECONDS)
        .build()

    WorkManager.getInstance(context).enqueueUniqueWork(
        "drain-hybrid-ai-queue",
        ExistingWorkPolicy.KEEP,
        work
    )
}

import android.content.Context
import android.net.ConnectivityManager
import android.net.NetworkCapabilities
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow

sealed interface HybridResult {
    data class Immediate(val text: String, val source: String = "ml-kit") : HybridResult
    data class Streaming(val deltaFlow: Flow<String>)                     : HybridResult
    data class Cached(val text: String)                                   : HybridResult
    data class Queued(val queueId: Long)                                  : HybridResult
}

class HybridAiRepository(
    private val context: Context,
    private val mlKitClient: MlKitNluClient,
    private val proxyClient: ClaudeProxyClient,
    private val db: HybridAiDatabase,
    private val sessionToken: String
) {
    suspend fun process(userText: String): Pair<HybridResult, HybridResult?> {
        // 1. Always run ML Kit — immediate, no network needed
        val mlKitEntities = runCatching { mlKitClient.extractEntities(userText) }
            .getOrDefault(emptyList())
        val immediateResult = HybridResult.Immediate(
            text = mlKitEntities.joinToString(", ") { it.text }.ifEmpty { "(no entities detected)" }
        )

        // 2. Check cache before going online or enqueueing
        val nowMs = System.currentTimeMillis()
        val cached = db.cachedResultDao().get(userText.sha256(), nowMs)
        if (cached != null) {
            return immediateResult to HybridResult.Cached(cached.response)
        }

        // 3. Online: stream Claude response
        if (isOnline()) {
            val stream = proxyClient.streamQuery(
                ProxyRequest(userText, sessionToken, "hybrid-nlu")
            )
            return immediateResult to HybridResult.Streaming(stream)
        }

        // 4. Offline: enqueue and schedule drain
        val queueId = db.pendingRequestDao().enqueue(
            PendingAiRequest(
                query = userText,
                sessionToken = sessionToken,
                routingContext = "hybrid-nlu",
                createdAtMs = nowMs
            )
        )
        scheduleDrainOnConnectivity(context)
        return immediateResult to HybridResult.Queued(queueId)
    }

    private fun isOnline(): Boolean {
        val cm = context.getSystemService(ConnectivityManager::class.java)
        val cap = cm.getNetworkCapabilities(cm.activeNetwork) ?: return false
        return cap.hasCapability(NetworkCapabilities.NET_CAPABILITY_INTERNET) &&
               cap.hasCapability(NetworkCapabilities.NET_CAPABILITY_VALIDATED)
    }
}

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

data class HybridUiState(
    val mlKitAnswer: String = "",
    val cloudAnswer: String = "",
    val cloudStatus: CloudStatus = CloudStatus.Idle
)

enum class CloudStatus { Idle, Streaming, Done, Queued, Error }

class HybridAiViewModel(
    private val repository: HybridAiRepository
) : ViewModel() {

    private val _state = MutableStateFlow(HybridUiState())
    val state: StateFlow<HybridUiState> = _state.asStateFlow()

    fun submit(userText: String) {
        viewModelScope.launch {
            val (immediate, cloud) = repository.process(userText)

            // Show ML Kit answer instantly
            _state.value = HybridUiState(
                mlKitAnswer = (immediate as HybridResult.Immediate).text,
                cloudStatus = CloudStatus.Streaming
            )

            when (cloud) {
                is HybridResult.Streaming -> {
                    var accumulated = ""
                    cloud.deltaFlow.collect { delta ->
                        accumulated += delta
                        _state.value = _state.value.copy(cloudAnswer = accumulated)
                    }
                    _state.value = _state.value.copy(cloudStatus = CloudStatus.Done)
                }
                is HybridResult.Cached -> {
                    _state.value = _state.value.copy(
                        cloudAnswer = cloud.text,
                        cloudStatus = CloudStatus.Done
                    )
                }
                is HybridResult.Queued -> {
                    _state.value = _state.value.copy(
                        cloudAnswer = "Request queued — will complete when online.",
                        cloudStatus = CloudStatus.Queued
                    )
                }
                else -> {}
            }
        }
    }
}

class PruneStaleEntriesWorker(
    ctx: Context, params: WorkerParameters
) : CoroutineWorker(ctx, params) {
    override suspend fun doWork(): Result {
        val db = HybridAiDatabase.getInstance(applicationContext)
        val nowMs = System.currentTimeMillis()
        db.pendingRequestDao().pruneExpired(nowMs)
        db.cachedResultDao().pruneExpired(nowMs)
        return Result.success()
    }
}

fun scheduleDailyPrune(context: Context) {
    val work = PeriodicWorkRequestBuilder<PruneStaleEntriesWorker>(1, java.util.concurrent.TimeUnit.DAYS)
        .build()
    WorkManager.getInstance(context).enqueueUniquePeriodicWork(
        "prune-hybrid-ai-db",
        ExistingPeriodicWorkPolicy.KEEP,
        work
    )
}

